import { useState, useEffect } from "react";
import { logoutUser } from "../services/auth";
import { useNavigate } from "react-router-dom";
import { getPolicies, addPolicy, deletePolicy } from "../services/firestore";

export default function TeamLeadDashboard() {
  const [policies, setPolicies] = useState([]);
  const [newTitle, setNewTitle] = useState("");
  const [newContent, setNewContent] = useState("");
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  const fetchLivePolicies = async () => {
    setLoading(true);
    const data = await getPolicies();
    setPolicies(data);
    setLoading(false);
  };

  useEffect(() => {
    fetchLivePolicies();
  }, []);

  const handleLogout = async () => {
    await logoutUser();
    navigate("/login");
  };

  const handleAddSubmit = async (e) => {
    e.preventDefault();
    if (!newTitle || !newContent) return;

    const success = await addPolicy(newTitle, newContent);
    if (success) {
      setNewTitle("");
      setNewContent("");
      fetchLivePolicies(); // Refresh the list
    }
  };

  const handleDelete = async (id) => {
    if (window.confirm("Are you sure you want to delete this policy?")) {
      const success = await deletePolicy(id);
      if (success) {
        fetchLivePolicies(); // Refresh the list
      }
    }
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-indigo-600 shadow-sm px-8 py-4 flex justify-between items-center text-white">
        <h1 className="text-xl font-bold">Team Lead Portal - KB Management</h1>
        <button 
          onClick={handleLogout}
          className="text-indigo-100 hover:text-white font-medium"
        >
          Sign Out
        </button>
      </nav>

      <div className="max-w-6xl mx-auto p-8 grid grid-cols-1 md:grid-cols-3 gap-8">

        {/* Left Column: Add New Policy */}
        <div className="md:col-span-1">
          <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-200">
            <h2 className="text-xl font-bold text-gray-800 mb-4">Add New Policy</h2>
            <form onSubmit={handleAddSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Policy Title</label>
                <input
                  type="text"
                  value={newTitle}
                  onChange={(e) => setNewTitle(e.target.value)}
                  placeholder="e.g., Escalation Routing"
                  className="w-full p-2 border border-gray-300 rounded focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Content / Steps</label>
                <textarea
                  value={newContent}
                  onChange={(e) => setNewContent(e.target.value)}
                  placeholder="Enter the step-by-step process..."
                  rows="5"
                  className="w-full p-2 border border-gray-300 rounded focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                ></textarea>
              </div>
              <button
                type="submit"
                className="w-full bg-indigo-600 text-white font-bold py-2 px-4 rounded hover:bg-indigo-700 transition-colors"
              >
                Publish to Knowledge Base
              </button>
            </form>
          </div>
        </div>

        {/* Right Column: Manage Existing Policies */}
        <div className="md:col-span-2">
          <h2 className="text-2xl font-bold text-gray-800 mb-4">Current Knowledge Base</h2>
          {loading ? (
            <p className="text-gray-500">Loading policies...</p>
          ) : (
            <div className="space-y-4">
              {policies.map(policy => (
                <div key={policy.id} className="bg-white p-6 rounded-lg shadow-sm border border-gray-200 flex justify-between items-start">
                  <div>
                    <h3 className="text-lg font-semibold text-gray-800">{policy.title}</h3>
                    <p className="text-gray-600 mt-1 text-sm">{policy.content}</p>
                  </div>
                  <button
                    onClick={() => handleDelete(policy.id)}
                    className="text-red-500 hover:text-red-700 text-sm font-medium ml-4 shrink-0"
                  >
                    Delete
                  </button>
                </div>
              ))}
              {policies.length === 0 && (
                <p className="text-gray-500">No policies found. Add one to get started.</p>
              )}
            </div>
          )}
        </div>

      </div>
    </div>
  );
}
